package com.lightevents.admin;
import com.lightevents.auth.*; import com.lightevents.events.*; import com.lightevents.payments.*; import com.lightevents.invoices.*; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/admin")
public class AdminController { private final AccountService accounts; private final AccountRepository accountRepo; private final EventRepository events; private final AttendeeRepository attendees; private final TransactionRepository transactions; private final ReservationRepository reservations; private final InvoiceRepository invoices; public AdminController(AccountService accounts, AccountRepository accountRepo, EventRepository events, AttendeeRepository attendees, TransactionRepository transactions, ReservationRepository reservations, InvoiceRepository invoices){this.accounts=accounts;this.accountRepo=accountRepo;this.events=events;this.attendees=attendees;this.transactions=transactions;this.reservations=reservations;this.invoices=invoices;}
 @PostMapping("/accounts") public AuthDtos.AccountResponse createAdminAccount(@RequestHeader(value="X-LightEvents-Token", required=false) String token, @RequestBody AuthDtos.RegisterRequest r){ accounts.requireAdmin(token); return accounts.response(accounts.registerAdmin(r)); }
 @PostMapping("/bootstrap") public AuthDtos.AccountResponse bootstrapAdmin(@RequestBody AuthDtos.RegisterRequest r){ if(accountRepo.findAll().stream().anyMatch(a->a.getRole()==AccountRole.ADMIN)) throw new RuntimeException("Admin already exists"); return accounts.response(accounts.registerAdmin(r)); }
 @GetMapping("/overview") public Map<String,Object> overview(@RequestHeader(value="X-LightEvents-Token", required=false) String token){ accounts.requireAdmin(token); return Map.of("organizers",accountRepo.findAll().stream().filter(a->a.getRole()==AccountRole.ORGANIZER).toList(),"events",events.findAll(),"attendees",attendees.findAll(),"reservations",reservations.findAll(),"transactions",transactions.findAll(),"invoices",invoices.findAll()); }
}
